INSERT INTO exercises (id, name, body_part, target_muscle, secondary_muscles, equipment, difficulty, instructions, form_cues, common_mistakes, sets_reps_guidance) VALUES
('barbell-bench-press','Barbell Bench Press','chest','pectoralis major',ARRAY['triceps','front deltoids'],'barbell','intermediate',ARRAY['Lie flat on a bench with your feet flat on the floor.','Grip the bar slightly wider than shoulder-width with an overhand grip.','Unrack the bar and hold it directly above your chest with arms fully extended.','Lower the bar slowly to your mid-chest, keeping elbows at about 45 degrees.','Press the bar back up to full extension, exhaling as you push.'],ARRAY['Keep your feet flat on the floor throughout','Maintain a slight arch in your lower back','Squeeze your shoulder blades together before unracking','Keep your wrists straight and directly above your elbows'],ARRAY['Flaring elbows out to 90 degrees','Bouncing the bar off your chest','Lifting your hips off the bench','Not retracting the shoulder blades'],'{"cutting":"3x12-15, moderate weight","bulking":"4x6-8, heavy weight","maintenance":"3x10, moderate weight"}'),
('dumbbell-bench-press','Dumbbell Bench Press','chest','pectoralis major',ARRAY['triceps','front deltoids'],'dumbbell','beginner',ARRAY['Sit on the edge of a bench holding a dumbbell on each knee.','Lie back, bringing the dumbbells to chest height with palms facing forward.','Press the dumbbells up until your arms are fully extended.','Lower them slowly back to the starting position.'],ARRAY['Keep your elbows at 45-75 degrees from your torso','Allow a full stretch at the bottom for greater range of motion','Press the dumbbells slightly inward at the top'],ARRAY['Letting dumbbells drift too far apart','Using momentum instead of controlled movement','Going too heavy before mastering the movement'],'{"cutting":"3x12-15, light-moderate weight","bulking":"4x8-10, heavy weight","maintenance":"3x10, moderate weight"}'),
('incline-barbell-press','Incline Barbell Press','chest','upper pectoralis',ARRAY['front deltoids','triceps'],'barbell','intermediate',ARRAY['Set an adjustable bench to 30-45 degrees incline.','Grip the bar slightly wider than shoulder-width.','Lower the bar to your upper chest near the clavicle.','Press back up to full extension.'],ARRAY['Keep the angle between 30-45 degrees to target upper chest','Pull the bar down rather than just letting it fall','Keep shoulder blades pinched throughout'],ARRAY['Setting the bench too steep','Letting the bar drift too far down the chest','Arching excessively off the bench'],'{"cutting":"3x12, moderate weight","bulking":"4x6-8, heavy weight","maintenance":"3x10, moderate weight"}'),
('dumbbell-flye','Dumbbell Flye','chest','pectoralis major',ARRAY['front deltoids'],'dumbbell','beginner',ARRAY['Lie flat on a bench holding dumbbells above your chest, palms facing each other.','With a slight bend in your elbows, lower the dumbbells in a wide arc.','Lower until you feel a stretch across your chest.','Bring the dumbbells back up in the same arc, squeezing your chest at the top.'],ARRAY['Maintain a fixed, slight elbow bend throughout','Think of hugging a large tree','Control the descent — 3 seconds down'],ARRAY['Bending the elbows too much','Going too heavy and losing control','Not feeling the stretch at the bottom'],'{"cutting":"3x15, light weight","bulking":"3x10-12, moderate weight","maintenance":"3x12, light-moderate weight"}'),
('cable-crossover','Cable Crossover','chest','pectoralis major',ARRAY['front deltoids'],'cable','intermediate',ARRAY['Set cables to the highest position on both sides of a cable station.','Stand in the center, grab both handles, and step forward slightly.','With a slight elbow bend, bring your hands down and together in front of your hips.','Slowly return to the starting position with arms extended.'],ARRAY['Keep a slight forward lean throughout','Squeeze the chest hard at the point of crossover','Control the return — don''t let the weight pull you back'],ARRAY['Standing too upright','Bending the elbows too much','Using momentum to swing the weight'],'{"cutting":"4x15, light weight","bulking":"3x12, moderate weight","maintenance":"3x12, moderate weight"}'),
('push-up','Push-Up','chest','pectoralis major',ARRAY['triceps','front deltoids','core'],'bodyweight','beginner',ARRAY['Start in a high plank with hands slightly wider than shoulder-width.','Keep your body in a straight line from head to heels.','Lower your chest to the floor by bending your elbows.','Push back up to full arm extension.'],ARRAY['Don''t let your hips sag or pike up','Keep your core braced throughout','Look slightly ahead, not straight down'],ARRAY['Letting hips drop or rise','Flaring elbows to 90 degrees','Not going through full range of motion'],'{"cutting":"4x15-20","bulking":"3x10-15 (add weight vest for resistance)","maintenance":"3x15"}'),
('decline-bench-press','Decline Bench Press','chest','lower pectoralis',ARRAY['triceps','front deltoids'],'barbell','intermediate',ARRAY['Set the bench to a 15-30 degree decline and secure your feet.','Grip the bar slightly wider than shoulder-width.','Lower the bar to your lower chest.','Press back up to full extension.'],ARRAY['Keep the decline mild — 15-30 degrees is enough','Maintain shoulder blade retraction throughout','The bar should touch your lower chest/sternum area'],ARRAY['Excessive decline angle','Losing shoulder blade retraction at the bottom','Bouncing the bar off the chest'],'{"cutting":"3x12, moderate weight","bulking":"4x6-8, heavy weight","maintenance":"3x10, moderate weight"}'),
('machine-chest-press','Machine Chest Press','chest','pectoralis major',ARRAY['triceps','front deltoids'],'machine','beginner',ARRAY['Adjust the seat so the handles are at chest height.','Grip the handles with palms facing forward.','Press the handles forward until arms are nearly fully extended.','Slowly return to the starting position.'],ARRAY['Keep your back flat against the pad','Don''t fully lock out elbows to maintain tension','Control the eccentric (return) portion'],ARRAY['Seat height too high or low','Arching back off the pad','Moving too fast on the return'],'{"cutting":"3x15, moderate weight","bulking":"4x8-10, heavy weight","maintenance":"3x12, moderate weight"}'),
('chest-dip','Chest Dip','chest','pectoralis major',ARRAY['triceps','front deltoids'],'bodyweight','intermediate',ARRAY['Grip parallel bars and support your body at arm''s length.','Lean forward at about 30 degrees to shift focus to chest.','Lower yourself by bending your elbows until you feel a chest stretch.','Push back up to the starting position.'],ARRAY['Lean forward to emphasize chest over triceps','Keep elbows slightly flared, not tucked tight','Full range of motion for maximum chest activation'],ARRAY['Staying too upright','Not going deep enough','Swinging or using momentum'],'{"cutting":"3x12-15","bulking":"4x8-10 (add weight belt if needed)","maintenance":"3x10-12"}'),
('pec-deck','Pec Deck Machine','chest','pectoralis major',ARRAY['front deltoids'],'machine','beginner',ARRAY['Sit in the machine with your back flat against the pad.','Place your forearms on the pads with elbows at 90 degrees.','Bring the pads together in front of your chest, squeezing the pecs.','Slowly return to the starting position for a full stretch.'],ARRAY['Keep your chest up and shoulders down','Pause and squeeze at full contraction','Let the pads go back far enough to feel a stretch'],ARRAY['Allowing shoulders to roll forward','Not getting a full range of motion','Going too heavy and losing form'],'{"cutting":"4x15, light-moderate weight","bulking":"3x12, moderate weight","maintenance":"3x12, moderate weight"}'),
('deadlift','Deadlift','back','erector spinae',ARRAY['glutes','hamstrings','lats','traps'],'barbell','advanced',ARRAY['Stand with feet hip-width apart, bar over mid-foot.','Hinge at the hips and grip the bar just outside your legs.','Brace your core, chest up, and drive the floor away with your feet.','Keep the bar close to your body as you stand up fully.','Hinge back down to lower the bar under control.'],ARRAY['Push the floor away — don''t think of pulling the bar up','Keep bar in contact with your shins throughout the lift','Lock out hips and knees simultaneously at the top','Take a big breath and brace hard before each rep'],ARRAY['Rounding the lower back','Bar drifting away from the body','Jerking the weight off the floor','Looking up too aggressively'],'{"cutting":"3x6-8, moderate weight","bulking":"4x3-5, heavy weight","maintenance":"3x5, moderate-heavy weight"}'),
('barbell-row','Barbell Row','back','latissimus dorsi',ARRAY['rhomboids','rear deltoids','biceps','traps'],'barbell','intermediate',ARRAY['Stand with feet shoulder-width apart, hinge forward about 45 degrees.','Grip the bar with an overhand grip, slightly wider than shoulder-width.','Pull the bar toward your lower chest/upper abdomen.','Squeeze your shoulder blades together at the top.','Lower the bar under control.'],ARRAY['Keep your back flat and parallel to the floor','Drive your elbows back, not your hands up','Initiate the pull by retracting your shoulder blades'],ARRAY['Using momentum and heaving the weight up','Standing too upright','Not squeezing at the top'],'{"cutting":"3x12, moderate weight","bulking":"4x6-8, heavy weight","maintenance":"3x10, moderate weight"}'),
('pull-up','Pull-Up','back','latissimus dorsi',ARRAY['biceps','rear deltoids','rhomboids'],'bodyweight','intermediate',ARRAY['Hang from a bar with an overhand grip, hands slightly wider than shoulders.','Engage your core and depress your shoulder blades.','Pull yourself up until your chin clears the bar.','Lower yourself slowly to a full hang.'],ARRAY['Think about pulling your elbows toward your hips','Avoid kipping or swinging','Full dead hang at the bottom for complete range of motion'],ARRAY['Using momentum to kip','Not going to full extension at the bottom','Shrugging the shoulders up'],'{"cutting":"4x max reps","bulking":"4x6-8 (add weight if needed)","maintenance":"3x8-10"}'),
('lat-pulldown','Lat Pulldown','back','latissimus dorsi',ARRAY['biceps','rear deltoids'],'cable','beginner',ARRAY['Sit at the pulldown station and secure your thighs under the pads.','Grip the bar wider than shoulder-width with an overhand grip.','Lean back slightly and pull the bar down to your upper chest.','Squeeze your lats at the bottom, then slowly return the bar up.'],ARRAY['Pull your elbows down and back, not just the bar down','Slight lean back is fine — don''t go past 30 degrees','Think about putting your shoulder blades in your back pockets'],ARRAY['Pulling the bar behind the neck','Using too much momentum','Letting the weight stack crash on each rep'],'{"cutting":"4x12-15, moderate weight","bulking":"4x8-10, heavy weight","maintenance":"3x10-12, moderate weight"}'),
('seated-cable-row','Seated Cable Row','back','rhomboids',ARRAY['lats','rear deltoids','biceps','traps'],'cable','beginner',ARRAY['Sit at the cable row station with feet on the platform, knees slightly bent.','Grip the handle and sit tall with your back straight.','Pull the handle toward your lower abdomen, keeping elbows close to your body.','Squeeze your shoulder blades together at full contraction.','Slowly extend your arms back to the starting position.'],ARRAY['Maintain an upright torso — don''t lean back excessively','Drive elbows behind your body, not flared out','Pause and hold the contraction for 1 second'],ARRAY['Rocking back and forth with the torso','Letting shoulders roll forward on the return','Pulling to the chest instead of abdomen'],'{"cutting":"3x15, moderate weight","bulking":"4x8-10, heavy weight","maintenance":"3x12, moderate weight"}'),
('dumbbell-row','Single-Arm Dumbbell Row','back','latissimus dorsi',ARRAY['rhomboids','biceps','rear deltoids'],'dumbbell','beginner',ARRAY['Place one knee and hand on a bench for support.','Hold a dumbbell in the opposite hand, arm hanging straight down.','Pull the dumbbell up toward your hip, keeping your elbow close to your body.','Lower the dumbbell back to the starting position.'],ARRAY['Keep your back flat and parallel to the floor','Drive your elbow toward the ceiling, not your hand toward your chest','Rotate your torso slightly at the top for full lat contraction'],ARRAY['Rotating the torso too much','Pulling the dumbbell toward the chest instead of the hip','Rushing the eccentric portion'],'{"cutting":"3x12 each side","bulking":"4x8-10 each side","maintenance":"3x10 each side"}'),
('t-bar-row','T-Bar Row','back','latissimus dorsi',ARRAY['rhomboids','traps','biceps'],'barbell','intermediate',ARRAY['Stand over the T-bar with feet straddling the bar.','Hinge forward to about 45 degrees and grip the handles.','Pull the bar toward your chest, keeping elbows close.','Lower the bar under control.'],ARRAY['Keep your chest up and back flat','Don''t jerk the weight — smooth, controlled pull','Squeeze shoulder blades together at the top'],ARRAY['Rounding the lower back','Using too much body momentum','Not achieving full range of motion'],'{"cutting":"3x12, moderate weight","bulking":"4x6-8, heavy weight","maintenance":"3x10, moderate weight"}'),
('face-pull','Face Pull','back','rear deltoids',ARRAY['rhomboids','traps','rotator cuff'],'cable','beginner',ARRAY['Set a cable to upper chest height with a rope attachment.','Grip the rope with both hands and step back.','Pull the rope toward your face, flaring elbows out to the sides.','Finish with hands beside your ears and elbows pointing out.','Slowly return to the starting position.'],ARRAY['Pull toward your nose or forehead, not your chin','Elbows should be higher than your hands at the finish','Keep your chest up and don''t lean back excessively'],ARRAY['Pulling toward the chin','Using too much weight','Allowing the elbows to drop below shoulder height'],'{"cutting":"4x15, light weight","bulking":"3x15, light-moderate weight","maintenance":"3x15, light weight"}'),
('hyperextension','Back Extension','back','erector spinae',ARRAY['glutes','hamstrings'],'bodyweight','beginner',ARRAY['Position yourself on the hyperextension bench with hips at the top pad.','Cross your arms over your chest or place hands behind your head.','Lower your torso until you feel a stretch in the hamstrings.','Raise your torso back up until your body is in a straight line.'],ARRAY['Do not hyperextend beyond a neutral spine at the top','Squeeze your glutes at the top of the movement','Control the descent — don''t just fall forward'],ARRAY['Hyperextending the lumbar spine at the top','Using momentum to swing up','Rounding the back excessively at the bottom'],'{"cutting":"3x15-20","bulking":"3x10-12 (hold a plate for resistance)","maintenance":"3x12-15"}'),
('good-morning','Good Morning','back','erector spinae',ARRAY['hamstrings','glutes'],'barbell','intermediate',ARRAY['Place a barbell across your upper traps, feet shoulder-width apart.','With a slight knee bend, hinge forward at the hips.','Lower your torso until nearly parallel to the floor.','Drive your hips forward to return to standing.'],ARRAY['Keep your back flat throughout','Push your hips backward as you hinge, not your chest forward','Keep the bar in contact with your traps throughout'],ARRAY['Rounding the lower back','Bending the knees too much','Using too much weight for this movement'],'{"cutting":"3x12, light weight","bulking":"4x8, moderate weight","maintenance":"3x10, light-moderate weight"}'),
('chest-supported-row','Chest-Supported Row','back','rhomboids',ARRAY['lats','rear deltoids','biceps'],'dumbbell','beginner',ARRAY['Set an incline bench to 30-45 degrees and lie chest-down on it.','Hold a dumbbell in each hand hanging below the bench.','Row the dumbbells up toward your hips, squeezing your shoulder blades.','Lower under control.'],ARRAY['Let your chest rest on the pad to eliminate cheating','Drive elbows back and up, not just up','Full stretch at the bottom for each rep'],ARRAY['Lifting your chest off the pad','Shrugging the shoulders up instead of retracting them','Not getting a full range of motion'],'{"cutting":"3x15, moderate weight","bulking":"4x10, moderate-heavy weight","maintenance":"3x12, moderate weight"}'),
('cable-pullover','Cable Pullover','back','latissimus dorsi',ARRAY['chest','triceps'],'cable','beginner',ARRAY['Set a cable to the highest position with a rope or bar attachment.','Stand facing the machine and grip the attachment with both hands.','With arms mostly straight, pull the attachment down toward your thighs.','Return under control to the starting position.'],ARRAY['Keep a slight bend in the elbows throughout','Feel the stretch in your lats at the top','Squeeze the lats hard at the bottom position'],ARRAY['Bending the elbows too much','Using too much weight and losing form','Not maintaining consistent back position'],'{"cutting":"3x15, light-moderate weight","bulking":"3x12, moderate weight","maintenance":"3x12, moderate weight"}'),
('shrug','Barbell Shrug','back','trapezius',ARRAY['upper traps','levator scapulae'],'barbell','beginner',ARRAY['Stand holding a barbell in front of you with an overhand grip.','With arms straight, shrug your shoulders straight up toward your ears.','Hold at the top for 1-2 seconds.','Lower your shoulders back down under control.'],ARRAY['Lift straight up — don''t roll the shoulders','Hold the contraction at the top','Keep your arms straight throughout'],ARRAY['Rolling the shoulders','Using too much weight with poor range of motion','Bending the elbows'],'{"cutting":"3x15, moderate weight","bulking":"4x8-10, heavy weight","maintenance":"3x12, moderate weight"}'),
('inverted-row','Inverted Row','back','rhomboids',ARRAY['lats','biceps','rear deltoids'],'bodyweight','beginner',ARRAY['Set a bar at about waist height in a squat rack.','Lie under the bar and grip it with an overhand grip.','Hang below the bar with your body in a straight line.','Pull your chest up to the bar, squeezing shoulder blades together.','Lower back down under control.'],ARRAY['Keep your body rigid like a plank','Pull to the chest, not the neck','Make it harder by lowering the bar or elevating your feet'],ARRAY['Letting the hips sag','Using momentum to swing up','Not achieving a full range of motion'],'{"cutting":"4x15","bulking":"4x10 (add weight vest or lower bar for difficulty)","maintenance":"3x12"}'),
('overhead-press','Overhead Press','shoulders','deltoids',ARRAY['triceps','upper traps','core'],'barbell','intermediate',ARRAY['Stand with feet shoulder-width apart and grip the bar at shoulder height.','Brace your core and press the bar straight up overhead.','Push your head through as the bar passes your face.','Lock out overhead with arms fully extended.','Lower the bar back to shoulder height under control.'],ARRAY['Keep your core tight and glutes squeezed to prevent lower back arch','The bar should travel in a straight vertical line','Push your head through the window at the top'],ARRAY['Excessive lower back arch','Bar path drifting forward','Pressing in front of the face instead of behind it'],'{"cutting":"3x12, moderate weight","bulking":"4x5-6, heavy weight","maintenance":"3x8, moderate weight"}'),
('dumbbell-lateral-raise','Dumbbell Lateral Raise','shoulders','lateral deltoids',ARRAY['front deltoids','traps'],'dumbbell','beginner',ARRAY['Stand holding dumbbells at your sides with palms facing your body.','With a slight elbow bend, raise your arms out to the sides.','Lift until your arms are parallel to the floor.','Lower slowly back to the starting position.'],ARRAY['Lead with your pinkies to target lateral head','Control the lowering — 3 seconds down','Don''t shrug your traps up as you raise'],ARRAY['Swinging the weight up with momentum','Going too heavy and losing control','Raising arms above shoulder height unnecessarily'],'{"cutting":"4x15, light weight","bulking":"4x12, moderate weight","maintenance":"3x12-15, light-moderate weight"}'),
('arnold-press','Arnold Press','shoulders','deltoids',ARRAY['triceps','upper traps'],'dumbbell','intermediate',ARRAY['Sit on a bench with dumbbells at shoulder height, palms facing you.','As you press up, rotate your palms outward.','Fully extend your arms overhead.','Reverse the rotation as you lower back to the starting position.'],ARRAY['The rotation should be smooth and continuous throughout the press','Keep your core braced and don''t arch your back','Control the eccentric — take 3 seconds to lower'],ARRAY['Rushing the rotation','Excessive back arch','Using too much weight which limits the rotation'],'{"cutting":"3x12, moderate weight","bulking":"4x8-10, moderate-heavy weight","maintenance":"3x10, moderate weight"}'),
('front-raise','Dumbbell Front Raise','shoulders','front deltoids',ARRAY['upper chest','traps'],'dumbbell','beginner',ARRAY['Stand holding dumbbells in front of your thighs, palms facing your body.','With a slight elbow bend, raise one or both dumbbells in front of you.','Lift to shoulder height.','Lower slowly back to the starting position.'],ARRAY['Don''t lean back as you raise the weight','Control the movement — no swinging','Palms can face down or toward each other'],ARRAY['Swinging the torso back','Going too heavy','Raising way above shoulder height'],'{"cutting":"3x15, light weight","bulking":"3x12, moderate weight","maintenance":"3x12, light-moderate weight"}'),
('reverse-flye','Reverse Dumbbell Flye','shoulders','rear deltoids',ARRAY['rhomboids','traps'],'dumbbell','beginner',ARRAY['Hinge forward at the hips until your torso is nearly parallel to the floor.','Hold dumbbells below your chest with palms facing each other.','With a slight elbow bend, raise the dumbbells out to the sides.','Squeeze your rear delts and rhomboids at the top.','Lower under control.'],ARRAY['Lead with your elbows, not your hands','Keep your back flat throughout','The movement is similar to spreading wings'],ARRAY['Rounding the back','Using momentum to swing the weight up','Going too heavy'],'{"cutting":"4x15, light weight","bulking":"3x12, moderate weight","maintenance":"3x15, light weight"}'),
('upright-row','Upright Row','shoulders','lateral deltoids',ARRAY['traps','biceps'],'barbell','beginner',ARRAY['Stand holding a barbell with an overhand grip, hands about 8-12 inches apart.','Pull the bar straight up toward your chin, leading with your elbows.','Raise until the bar is at upper chest/chin height.','Lower the bar back down under control.'],ARRAY['Keep the bar close to your body throughout','Elbows should always be above your hands','Don''t use momentum — slow and controlled'],ARRAY['Using too narrow a grip','Pulling the bar too high above the chin','Letting the bar drift away from the body'],'{"cutting":"3x15, moderate weight","bulking":"4x10, moderate weight","maintenance":"3x12, moderate weight"}'),
('cable-lateral-raise','Cable Lateral Raise','shoulders','lateral deltoids',ARRAY['front deltoids','traps'],'cable','beginner',ARRAY['Set a cable to the lowest position and attach a single handle.','Stand sideways to the machine and grab the handle with your far hand.','Raise your arm out to the side to shoulder height.','Slowly lower back down.'],ARRAY['Constant tension from the cable throughout the movement','Slight forward lean to better target the lateral head','Don''t shrug your shoulder at the top'],ARRAY['Standing too close to the machine','Shrugging at the top','Bending the elbow too much'],'{"cutting":"4x15 each side","bulking":"3x12 each side","maintenance":"3x12-15 each side"}'),
('machine-shoulder-press','Machine Shoulder Press','shoulders','deltoids',ARRAY['triceps','upper traps'],'machine','beginner',ARRAY['Adjust the seat so handles are at shoulder level.','Grip the handles and press upward until arms are extended.','Lower back to shoulder level under control.'],ARRAY['Keep your back flat against the pad','Don''t fully lock out your elbows','Exhale as you press up'],ARRAY['Arching away from the back pad','Using too much weight and losing posture','Going too fast on the eccentric'],'{"cutting":"3x15, moderate weight","bulking":"4x8-10, heavy weight","maintenance":"3x10-12, moderate weight"}'),
('barbell-curl','Barbell Curl','arms','biceps brachii',ARRAY['brachialis','forearms'],'barbell','beginner',ARRAY['Stand holding a barbell with an underhand grip, hands shoulder-width apart.','Keeping your elbows pinned at your sides, curl the bar up to shoulder height.','Squeeze your biceps at the top.','Slowly lower the bar back to the starting position.'],ARRAY['Keep your upper arms completely still','Don''t swing your hips or lean back','Take 2-3 seconds to lower the weight'],ARRAY['Swinging the body to lift the weight','Letting elbows drift forward','Not achieving full range of motion'],'{"cutting":"3x15, moderate weight","bulking":"4x8-10, heavy weight","maintenance":"3x10-12, moderate weight"}'),
('dumbbell-curl','Dumbbell Bicep Curl','arms','biceps brachii',ARRAY['brachialis','forearms'],'dumbbell','beginner',ARRAY['Stand holding dumbbells at your sides, palms facing forward.','Keeping your elbows stationary, curl both dumbbells up toward your shoulders.','Squeeze your biceps at the top.','Lower slowly back to full extension.'],ARRAY['Supinate your wrists as you curl for peak contraction','Keep your elbows stationary at your sides','Full extension at the bottom for complete stretch'],ARRAY['Swinging the arms using momentum','Not supinating the wrist','Partial range of motion'],'{"cutting":"3x15 each arm","bulking":"4x10, moderate weight","maintenance":"3x12, moderate weight"}'),
('hammer-curl','Hammer Curl','arms','brachialis',ARRAY['biceps brachii','forearms'],'dumbbell','beginner',ARRAY['Stand holding dumbbells at your sides, palms facing each other.','Curl the dumbbells upward without rotating your wrists.','Squeeze at the top.','Lower back down slowly.'],ARRAY['Keep palms facing each other throughout the movement','Elbows stay fixed at your sides','This hits the brachialis and brachioradialis more than a regular curl'],ARRAY['Rotating the wrist','Using momentum to swing the weight','Going too heavy'],'{"cutting":"3x15","bulking":"4x10, moderate weight","maintenance":"3x12"}'),
('tricep-pushdown','Tricep Pushdown','arms','triceps brachii',ARRAY['forearms'],'cable','beginner',ARRAY['Set a cable to the highest position with a straight bar or rope attachment.','Grip the bar with an overhand grip, elbows tucked at your sides.','Push the bar down until your arms are fully extended.','Slowly return to the starting position.'],ARRAY['Keep your elbows stationary and pinned to your sides','Fully extend the arms at the bottom for peak contraction','Don''t lean forward excessively'],ARRAY['Letting elbows flare out or drift forward','Using body weight to push down','Not fully extending arms'],'{"cutting":"4x15, moderate weight","bulking":"4x10-12, moderate weight","maintenance":"3x12, moderate weight"}'),
('skull-crusher','Skull Crusher','arms','triceps brachii',ARRAY[],'barbell','intermediate',ARRAY['Lie on a bench holding an EZ-bar or straight bar with arms extended above your chest.','Keeping your upper arms perpendicular to the floor, bend your elbows.','Lower the bar toward your forehead.','Extend your arms back to the starting position.'],ARRAY['Upper arms remain fixed — only the forearms move','Keep your elbows shoulder-width apart, don''t let them flare','Control the descent — this is a vulnerable position'],ARRAY['Elbows flaring out widely','Moving the upper arms instead of just the forearms','Dropping the weight too fast'],'{"cutting":"3x15, light-moderate weight","bulking":"4x10, moderate weight","maintenance":"3x12, moderate weight"}'),
('tricep-dip','Tricep Dip','arms','triceps brachii',ARRAY['chest','front deltoids'],'bodyweight','beginner',ARRAY['Place your hands on a bench behind you, feet on the floor.','Lower your hips toward the floor by bending your elbows.','Keep your back close to the bench.','Push back up to the starting position.'],ARRAY['Keep your hips close to the bench to target triceps','Don''t shrug your shoulders up','Keep elbows pointing straight back, not out'],ARRAY['Hips drifting too far from the bench','Shoulders shrugging up','Elbows flaring out'],'{"cutting":"4x15-20","bulking":"4x10-15 (add weight for resistance)","maintenance":"3x12-15"}'),
('overhead-tricep-extension','Overhead Tricep Extension','arms','triceps brachii',ARRAY[],'dumbbell','beginner',ARRAY['Hold a dumbbell with both hands and raise it overhead.','Keeping your upper arms beside your head, bend your elbows.','Lower the dumbbell behind your head until you feel a stretch.','Extend your arms back to the starting position.'],ARRAY['Keep your elbows pointing toward the ceiling','Don''t let the elbows flare out to the sides','Get a full stretch at the bottom for the long head'],ARRAY['Letting elbows flare outward','Moving the upper arms during the exercise','Using too much weight'],'{"cutting":"3x15, light-moderate weight","bulking":"4x10, moderate weight","maintenance":"3x12, moderate weight"}'),
('preacher-curl','Preacher Curl','arms','biceps brachii',ARRAY['brachialis'],'machine','beginner',ARRAY['Sit at the preacher bench and place your upper arms on the pad.','Grip the bar with an underhand grip.','Curl the bar upward, stopping just before vertical.','Lower slowly under control.'],ARRAY['Keep your upper arms pressed firmly against the pad','Don''t fully lock out at the bottom — keep tension on the biceps','Control the eccentric portion'],ARRAY['Letting arms slip off the pad','Locking out at the bottom','Using momentum'],'{"cutting":"3x15, light-moderate weight","bulking":"4x10, moderate weight","maintenance":"3x12, moderate weight"}'),
('squat','Barbell Back Squat','legs','quadriceps',ARRAY['glutes','hamstrings','core','adductors'],'barbell','intermediate',ARRAY['Place the barbell on your upper traps and stand with feet shoulder-width apart.','Brace your core and take a deep breath.','Push your knees out and descend by sitting back and down.','Lower until your thighs are at least parallel to the floor.','Drive through your heels to return to standing.'],ARRAY['Knees should track over your toes throughout','Keep your chest up and torso as upright as possible','Push the floor away — don''t think of standing up'],ARRAY['Knees caving inward','Heels rising off the floor','Not reaching parallel depth','Excessive forward lean'],'{"cutting":"3x12, moderate weight","bulking":"5x5, heavy weight","maintenance":"4x8, moderate-heavy weight"}'),
('front-squat','Front Squat','legs','quadriceps',ARRAY['glutes','core','upper back'],'barbell','advanced',ARRAY['Rest the barbell on your front deltoids, elbows high and forward.','Stand with feet shoulder-width apart.','Descend by sitting straight down, keeping a very upright torso.','Lower until thighs are parallel or below.','Drive through your heels to stand.'],ARRAY['Keep elbows up — if they drop, the bar will fall','Much more upright torso than a back squat','Knees should travel forward over toes more than in back squat'],ARRAY['Elbows dropping and bar rolling forward','Excessive forward lean','Not enough ankle mobility'],'{"cutting":"3x10, moderate weight","bulking":"4x5-6, heavy weight","maintenance":"3x8, moderate weight"}'),
('goblet-squat','Goblet Squat','legs','quadriceps',ARRAY['glutes','core','adductors'],'kettlebell','beginner',ARRAY['Hold a kettlebell vertically at your chest with both hands.','Stand with feet slightly wider than shoulder-width, toes turned out.','Sit down between your heels, keeping your chest up.','Drive through your heels to return to standing.'],ARRAY['Use your elbows to push your knees out at the bottom','Keep the kettlebell close to your chest throughout','A great teaching tool for squat mechanics'],ARRAY['Letting knees cave inward','Losing upright torso position','Not achieving full depth'],'{"cutting":"3x15, moderate weight","bulking":"4x10, heavy kettlebell","maintenance":"3x12, moderate weight"}'),
('leg-press','Leg Press','legs','quadriceps',ARRAY['glutes','hamstrings'],'machine','beginner',ARRAY['Sit in the leg press machine with your back flat against the pad.','Place your feet shoulder-width apart on the platform.','Release the safety handles and lower the platform toward your chest.','Press the platform back up until your legs are nearly fully extended.','Re-engage safety handles before exiting.'],ARRAY['Don''t lock your knees out at the top','Keep your lower back pressed against the pad throughout','Foot position changes emphasis: high feet = more glutes/hamstrings, low feet = more quads'],ARRAY['Going too heavy and having knees cave','Letting lower back round off the pad','Partial range of motion'],'{"cutting":"4x15, moderate weight","bulking":"4x8-10, heavy weight","maintenance":"3x12, moderate weight"}'),
('lunge','Barbell Lunge','legs','quadriceps',ARRAY['glutes','hamstrings','core'],'barbell','intermediate',ARRAY['Place the barbell across your upper traps.','Step forward with one leg and lower your back knee toward the floor.','Keep your front knee tracking over your toes.','Push through your front heel to return to standing.','Repeat on the other side.'],ARRAY['Keep your torso upright throughout','Front knee should not go past your toes','Back knee hovers just above the floor'],ARRAY['Leaning too far forward','Front knee caving inward','Taking too short a step'],'{"cutting":"3x12 each leg","bulking":"4x8 each leg","maintenance":"3x10 each leg"}'),
('romanian-deadlift','Romanian Deadlift','legs','hamstrings',ARRAY['glutes','erector spinae','adductors'],'barbell','intermediate',ARRAY['Stand holding a barbell with an overhand grip, feet hip-width apart.','With a slight knee bend, hinge forward by pushing your hips back.','Lower the bar along your legs until you feel a deep hamstring stretch.','Drive your hips forward to return to standing.'],ARRAY['Push your hips back — don''t just bend over','Keep the bar close to your legs throughout','Maintain a neutral spine — no rounding'],ARRAY['Rounding the lower back','Bending the knees too much','Not feeling the hamstring stretch'],'{"cutting":"3x15, moderate weight","bulking":"4x8-10, heavy weight","maintenance":"3x10-12, moderate weight"}'),
('leg-curl','Lying Leg Curl','legs','hamstrings',ARRAY['calves'],'machine','beginner',ARRAY['Lie face down on the leg curl machine with the pad just below your calves.','Curl your heels toward your glutes.','Pause at the top, squeezing your hamstrings.','Lower slowly back to the starting position.'],ARRAY['Hips stay flat on the pad throughout','Control the eccentric — 3 seconds down','Point toes away to increase hamstring activation'],ARRAY['Hips rising off the pad','Using momentum to swing the weight','Not achieving full range of motion'],'{"cutting":"4x15, moderate weight","bulking":"4x10, moderate-heavy weight","maintenance":"3x12, moderate weight"}'),
('hip-thrust','Barbell Hip Thrust','legs','glutes',ARRAY['hamstrings','core'],'barbell','intermediate',ARRAY['Sit on the floor with your upper back against a bench.','Roll a barbell over your hips.','Drive your hips upward by squeezing your glutes.','Your upper back should pivot on the bench.','Lower your hips back toward the floor.'],ARRAY['Chin to chest at the top to prevent back extension','Drive through your heels, not your toes','Fully extend hips at the top — get a hard glute squeeze'],ARRAY['Looking up','Pushing through the toes instead of heels','Not fully extending at the top'],'{"cutting":"4x15, moderate weight","bulking":"4x8-10, heavy weight","maintenance":"3x12, moderate weight"}'),
('glute-bridge','Glute Bridge','legs','glutes',ARRAY['hamstrings','core'],'bodyweight','beginner',ARRAY['Lie on your back with knees bent and feet flat on the floor.','Drive your hips up toward the ceiling by squeezing your glutes.','Hold at the top for 1-2 seconds.','Lower your hips back to the floor.'],ARRAY['Squeeze glutes hard at the top','Feet should be hip-width apart','Don''t let your back arch excessively'],ARRAY['Pushing through the toes instead of heels','Hamstrings doing the work instead of glutes','Not fully extending at the top'],'{"cutting":"4x20","bulking":"4x15 (add weight plate on hips)","maintenance":"3x15-20"}'),
('calf-raise','Standing Calf Raise','legs','gastrocnemius',ARRAY['soleus'],'machine','beginner',ARRAY['Stand on the edge of a step or calf raise machine, heels hanging off.','Rise up onto your toes as high as possible.','Pause at the top.','Lower your heels below the platform level for a full stretch.'],ARRAY['Full range of motion — get the heel all the way down','Pause at the top and squeeze the calf hard','Straight legs target the gastrocnemius more'],ARRAY['Not going through full range of motion','Bouncing at the bottom','Going too fast'],'{"cutting":"4x20, moderate weight","bulking":"4x12-15, heavy weight","maintenance":"3x15-20, moderate weight"}'),
('seated-calf-raise','Seated Calf Raise','legs','soleus',ARRAY['gastrocnemius'],'machine','beginner',ARRAY['Sit in the seated calf raise machine with the pad on your lower thighs.','Rise up onto your toes as high as possible.','Pause and squeeze at the top.','Lower your heels to get a full stretch.'],ARRAY['Bent knees target the soleus','Full range of motion is critical','Slow, controlled reps are more effective than bouncing'],ARRAY['Short range of motion','Bouncing the weight','Not feeling a stretch at the bottom'],'{"cutting":"4x20, moderate weight","bulking":"4x12, heavy weight","maintenance":"3x15-20"}'),
('leg-extension','Leg Extension','legs','quadriceps',ARRAY[],'machine','beginner',ARRAY['Sit in the leg extension machine with the pad on your shins.','Extend your legs until nearly fully straight.','Pause and squeeze your quads at the top.','Lower slowly back to the starting position.'],ARRAY['Pause at the top for peak quad contraction','Control the eccentric — don''t just let the weight fall','Keep your back against the pad'],ARRAY['Swinging the legs up with momentum','Not fully extending at the top','Going too heavy'],'{"cutting":"4x15, moderate weight","bulking":"4x10-12, moderate-heavy weight","maintenance":"3x12, moderate weight"}'),
('sumo-deadlift','Sumo Deadlift','legs','adductors',ARRAY['glutes','quadriceps','hamstrings','erector spinae'],'barbell','advanced',ARRAY['Stand with feet much wider than shoulder-width, toes pointed out 45 degrees.','Grip the bar inside your legs with a double overhand or mixed grip.','Keep your torso more upright than a conventional deadlift.','Drive the floor away and stand up fully.','Lower the bar under control.'],ARRAY['Push your knees out over your toes throughout','More upright torso compared to conventional','Spread the floor apart with your feet as you lift'],ARRAY['Knees caving inward','Not enough hip external rotation','Hips shooting up before the bar leaves the floor'],'{"cutting":"3x8, moderate weight","bulking":"4x4-5, heavy weight","maintenance":"3x6, moderate-heavy weight"}'),
('bulgarian-split-squat','Bulgarian Split Squat','legs','quadriceps',ARRAY['glutes','hamstrings','core'],'dumbbell','intermediate',ARRAY['Stand with your back to a bench, holding dumbbells at your sides.','Place one foot on the bench behind you.','Lower your back knee toward the floor.','Drive through your front heel to stand back up.'],ARRAY['Keep your front foot far enough forward','Keep your torso upright','Control the descent — don''t just drop down'],ARRAY['Front knee caving inward','Foot too close to the bench causing knee to go past toes','Excessive forward lean'],'{"cutting":"3x12 each leg","bulking":"4x8 each leg","maintenance":"3x10 each leg"}'),
('step-up','Dumbbell Step-Up','legs','quadriceps',ARRAY['glutes','hamstrings'],'dumbbell','beginner',ARRAY['Hold dumbbells at your sides and stand in front of a bench or box.','Step up with one foot, pressing through the heel to stand fully.','Bring your other foot up to the bench.','Step back down with the same leg.'],ARRAY['Drive through the heel of the leg on the bench','Don''t push off with the back foot','Keep your torso upright'],ARRAY['Pushing off the back foot','Leaning forward excessively','Using a platform that''s too low'],'{"cutting":"3x15 each leg","bulking":"4x10 each leg","maintenance":"3x12 each leg"}'),
('nordic-hamstring-curl','Nordic Hamstring Curl','legs','hamstrings',ARRAY['glutes','calves'],'bodyweight','advanced',ARRAY['Kneel on a mat with your ankles anchored under a bar or held by a partner.','Keep your body straight from knees to head.','Slowly lower your torso toward the floor by allowing your knees to extend.','Catch yourself with your hands if needed, then curl back up using your hamstrings.'],ARRAY['The eccentric is where most of the benefit comes from','Keep your hips extended — don''t bend at the hips','Most people need to start with slow eccentrics only'],ARRAY['Bending at the hips','Going too fast','Not having ankles properly anchored'],'{"cutting":"3x5-8 (eccentric focus)","bulking":"3x5-8","maintenance":"3x6"}'),
('wall-sit','Wall Sit','legs','quadriceps',ARRAY['glutes','hamstrings','calves'],'bodyweight','beginner',ARRAY['Stand with your back against a wall.','Slide down until your thighs are parallel to the floor.','Hold this position for the target duration.','Push through your heels and stand back up.'],ARRAY['Thighs should be parallel to the floor','Keep your back flat against the wall','Don''t rest your hands on your knees'],ARRAY['Thighs not reaching parallel','Leaning away from the wall','Resting hands on knees'],'{"cutting":"4x45-60 seconds","bulking":"3x60 seconds (add weight plate on thighs)","maintenance":"3x45-60 seconds"}'),
('glute-kickback','Cable Glute Kickback','legs','glutes',ARRAY['hamstrings'],'cable','beginner',ARRAY['Attach an ankle cuff to a low cable.','Face the machine holding the frame for balance.','Kick your working leg straight back and up, squeezing your glute.','Return to the starting position under control.'],ARRAY['Keep a slight bend in the standing knee','Don''t rotate your hip — kick straight back','Squeeze the glute hard at the top of the movement'],ARRAY['Using too much weight and losing control','Rotating the hip outward','Not getting full extension'],'{"cutting":"4x15 each side","bulking":"3x12 each side","maintenance":"3x15 each side"}'),
('adductor-machine','Adductor Machine','legs','adductors',ARRAY[],'machine','beginner',ARRAY['Sit in the adductor machine with the pads on the insides of your knees.','Start with legs spread wide.','Squeeze your legs together against the resistance.','Slowly return to the starting position.'],ARRAY['Keep your back flat against the pad','Controlled movement — no jerking','Full range of motion in both directions'],ARRAY['Using momentum to bring the legs together','Not getting a full stretch at the start','Going too heavy'],'{"cutting":"3x15, moderate weight","bulking":"3x12, moderate weight","maintenance":"3x12-15, moderate weight"}'),
('plank','Plank','core','transverse abdominis',ARRAY['rectus abdominis','obliques','glutes','shoulders'],'bodyweight','beginner',ARRAY['Start in a push-up position and lower onto your forearms.','Keep your body in a straight line from head to heels.','Engage your core and glutes.','Hold for the target duration.'],ARRAY['Don''t let your hips sag or pike up','Squeeze your glutes and brace your abs','Look at the floor to keep your neck neutral'],ARRAY['Hips sagging toward the floor','Hips piked up too high','Holding the breath'],'{"cutting":"4x45-60 seconds","bulking":"3x60 seconds","maintenance":"3x45-60 seconds"}'),
('crunch','Crunch','core','rectus abdominis',ARRAY['obliques'],'bodyweight','beginner',ARRAY['Lie on your back with knees bent and feet flat on the floor.','Place your hands behind your head without pulling your neck.','Curl your shoulders off the floor by contracting your abs.','Hold the contraction briefly, then lower back down.'],ARRAY['Focus on curling your ribcage toward your pelvis','Don''t pull on your neck with your hands','Exhale as you crunch up'],ARRAY['Pulling the neck with the hands','Using hip flexors instead of abs','Jerking up instead of curling'],'{"cutting":"4x20","bulking":"3x20 (hold a weight plate for resistance)","maintenance":"3x20"}'),
('russian-twist','Russian Twist','core','obliques',ARRAY['rectus abdominis'],'bodyweight','beginner',ARRAY['Sit on the floor with knees bent, lean back to about 45 degrees.','Hold your hands together or hold a weight in front of you.','Rotate your torso to one side, then the other.','Each side rotation counts as one rep.'],ARRAY['The rotation comes from your torso, not your arms','Keep your feet elevated for more difficulty','Keep your lower back from rounding'],ARRAY['Moving the arms instead of rotating the torso','Letting the lower back round','Going through the motion without core engagement'],'{"cutting":"4x20 each side","bulking":"3x15 each side (hold a medicine ball)","maintenance":"3x20 each side"}'),
('hanging-leg-raise','Hanging Leg Raise','core','rectus abdominis',ARRAY['hip flexors','obliques'],'bodyweight','intermediate',ARRAY['Hang from a pull-up bar with an overhand grip.','Engage your core and raise your legs straight up to 90 degrees.','Hold briefly at the top.','Lower your legs slowly without swinging.'],ARRAY['No swinging — control the movement completely','Posterior pelvic tilt at the top for more ab activation','Beginners can bend the knees to make it easier'],ARRAY['Swinging the body for momentum','Not controlling the eccentric','Using hip flexors exclusively without involving the abs'],'{"cutting":"4x15","bulking":"3x10-15 (add ankle weights for resistance)","maintenance":"3x12-15"}'),
('ab-wheel-rollout','Ab Wheel Rollout','core','transverse abdominis',ARRAY['rectus abdominis','lats','shoulders'],'bodyweight','advanced',ARRAY['Kneel on a mat holding the ab wheel in front of you.','Roll the wheel forward, extending your body toward the floor.','Extend as far as you can while maintaining a neutral spine.','Pull the wheel back toward your knees using your abs and lats.'],ARRAY['Don''t let your lower back arch — keep it neutral','Pull the wheel back using your abs, not your hip flexors','Start with short range of motion and increase gradually'],ARRAY['Excessive lower back arch','Going too far too soon','Using arm strength instead of core'],'{"cutting":"3x10-12","bulking":"3x10-15","maintenance":"3x10"}'),
('bicycle-crunch','Bicycle Crunch','core','obliques',ARRAY['rectus abdominis','hip flexors'],'bodyweight','beginner',ARRAY['Lie on your back and bring your knees to your chest.','Place your hands behind your head.','Extend one leg out while rotating your upper body toward the opposite knee.','Alternate sides in a pedaling motion.'],ARRAY['The rotation should come from your torso, not your elbows','Keep the movement slow and controlled for maximum activation','Keep the lower back pressed to the floor'],ARRAY['Pulling on the neck','Moving elbows instead of rotating the torso','Going too fast and losing the mind-muscle connection'],'{"cutting":"3x20 each side","bulking":"3x20 each side","maintenance":"3x20 each side"}'),
('cable-crunch','Cable Crunch','core','rectus abdominis',ARRAY['obliques'],'cable','intermediate',ARRAY['Kneel in front of a high cable with a rope attachment.','Hold the rope at the sides of your head.','Crunch downward by flexing your spine, bringing your elbows toward your knees.','Slowly return to the starting position.'],ARRAY['Hinge at the hips AND flex the spine — it''s not just a hip hinge','Keep your hips stationary throughout','Really focus on curling the ribcage toward the pelvis'],ARRAY['Hinging at the hips only','Moving the hips forward and back','Not getting a full range of motion'],'{"cutting":"4x15, moderate weight","bulking":"4x12, moderate weight","maintenance":"3x15, moderate weight"}'),
('dead-bug','Dead Bug','core','transverse abdominis',ARRAY['rectus abdominis','hip flexors'],'bodyweight','beginner',ARRAY['Lie on your back, arms extended toward the ceiling, knees bent 90 degrees.','Press your lower back into the floor and maintain that pressure.','Slowly extend one arm back and the opposite leg out simultaneously.','Return and repeat on the other side.'],ARRAY['Lower back must stay pressed to the floor throughout','Move slowly and deliberately','Breathe out as you extend the limbs'],ARRAY['Lower back arching off the floor','Moving too fast','Not fully extending the arm and leg'],'{"cutting":"3x10 each side","bulking":"3x10 each side","maintenance":"3x10 each side"}'),
('side-plank','Side Plank','core','obliques',ARRAY['transverse abdominis','glutes','shoulders'],'bodyweight','beginner',ARRAY['Lie on your side and prop yourself up on your forearm.','Stack your feet or stagger them for stability.','Raise your hips off the floor to form a straight line from head to heels.','Hold for the target duration.'],ARRAY['Keep your hips from rotating forward or backward','Drive your hip up toward the ceiling — don''t let it sag','Keep your neck neutral'],ARRAY['Hips sagging toward the floor','Hips rotating','Neck out of alignment'],'{"cutting":"3x30-45 seconds each side","bulking":"3x45 seconds each side","maintenance":"3x30-45 seconds each side"}'),
('burpee','Burpee','full body','full body',ARRAY['chest','shoulders','triceps','core','quads','glutes'],'bodyweight','intermediate',ARRAY['Start standing, then squat down and place hands on the floor.','Jump your feet back into a push-up position.','Perform a push-up.','Jump your feet back toward your hands.','Explode upward into a jump with arms overhead.'],ARRAY['Keep your core engaged throughout','Land softly from the jump to protect your joints','Set a sustainable pace rather than sprinting and stopping'],ARRAY['Skipping the push-up','Collapsing the hips during the push-up phase','Landing heavily from the jump'],'{"cutting":"4x10-15","bulking":"3x10","maintenance":"3x10-12"}'),
('clean-and-press','Clean and Press','full body','full body',ARRAY['shoulders','traps','quads','core'],'barbell','advanced',ARRAY['Stand with the bar at mid-shin, grip just outside legs.','Explosively pull the bar upward, using hip extension and a high pull.','Drop under the bar and catch it at shoulder height.','From the front rack, press the bar overhead to full extension.','Lower back to the starting position.'],ARRAY['The power comes from the hips, not the arms','Stay on your heels through the pull phase','A strong front rack position is essential'],ARRAY['Pulling with the arms too early','A poor front rack position','Not using hip drive'],'{"cutting":"3x6, moderate weight","bulking":"4x4, heavy weight","maintenance":"3x5, moderate weight"}'),
('kettlebell-swing','Kettlebell Swing','full body','glutes',ARRAY['hamstrings','core','shoulders','back'],'kettlebell','intermediate',ARRAY['Stand with feet shoulder-width apart, kettlebell on the floor in front of you.','Hinge at the hips and grip the kettlebell.','Hike the kettlebell back between your legs.','Drive your hips forward explosively to swing the kettlebell to chest height.','Let the kettlebell swing back and repeat.'],ARRAY['This is a hip hinge, not a squat','Power comes entirely from the hip snap','Your arms are just a guide — don''t use them to lift the weight'],ARRAY['Squatting instead of hinging','Using arms to lift the kettlebell','Rounding the lower back'],'{"cutting":"4x15-20","bulking":"4x10-12, heavy kettlebell","maintenance":"3x15"}'),
('thruster','Thruster','full body','quadriceps',ARRAY['glutes','shoulders','triceps','core'],'barbell','advanced',ARRAY['Hold the barbell in a front rack position at shoulder height.','Squat down until thighs are parallel to the floor.','Use the momentum from standing up to drive the bar overhead.','Lock out arms overhead at the top.','Lower bar back to shoulders and repeat.'],ARRAY['The transition from squat to press should be seamless','Drive from the hips to add momentum to the press','Strong front rack and core brace are essential'],ARRAY['Pausing at the top of the squat before pressing','Pressing independently without using leg drive','A weak front rack position'],'{"cutting":"3x10, moderate weight","bulking":"4x6, moderate-heavy weight","maintenance":"3x8, moderate weight"}'),
('farmers-carry','Farmer''s Carry','full body','trapezius',ARRAY['forearms','core','glutes','shoulders'],'dumbbell','beginner',ARRAY['Pick up a heavy dumbbell in each hand.','Stand tall with your shoulders back and core braced.','Walk forward for the target distance or time.','Keep your steps controlled and your posture tall throughout.'],ARRAY['Don''t let the dumbbells cause you to lean to one side','Keep your shoulders packed down and back','Short, controlled steps'],ARRAY['Leaning to one side','Shrugging the shoulders up','Taking too large steps and losing stability'],'{"cutting":"4x40 meters","bulking":"4x20-30 meters, heavy","maintenance":"3x30-40 meters"}'),
('box-jump','Box Jump','full body','quadriceps',ARRAY['glutes','hamstrings','calves'],'bodyweight','intermediate',ARRAY['Stand facing a sturdy box or platform.','Bend your knees and swing your arms back.','Explode upward, swinging arms forward for momentum.','Land softly on the box with both feet.','Step down carefully.'],ARRAY['Land softly — bend knees to absorb the impact','Full hip extension at the top of the jump','Step down, don''t jump down, to reduce joint stress'],ARRAY['Landing hard with straight legs','Using a box that is too high before mastering the pattern','Jumping down instead of stepping'],'{"cutting":"4x8","bulking":"5x5 (maximum height box)","maintenance":"3x8"}'),
('resistance-band-squat','Resistance Band Squat','legs','quadriceps',ARRAY['glutes','hamstrings','abductors'],'resistance band','beginner',ARRAY['Place a resistance band just above your knees.','Stand with feet shoulder-width apart.','Push your knees out against the band resistance as you squat down.','Drive back up to standing, maintaining outward knee pressure.'],ARRAY['Actively push knees outward against the band','This improves glute activation and knee tracking','Keep your chest up and heels flat'],ARRAY['Letting the band collapse the knees inward','Not maintaining tension against the band','Using too light a band'],'{"cutting":"3x20","bulking":"3x15 (use heavier band or hold dumbbells)","maintenance":"3x15-20"}'),
('resistance-band-pull-apart','Resistance Band Pull-Apart','back','rear deltoids',ARRAY['rhomboids','traps'],'resistance band','beginner',ARRAY['Hold a resistance band with both hands at shoulder height, arms extended.','Pull the band apart by moving your hands out to the sides.','Squeeze your shoulder blades together at full extension.','Return slowly to the starting position.'],ARRAY['Keep your arms straight throughout','Squeeze the rear delts hard at full extension','Control the return — don''t let the band snap back'],ARRAY['Bending the elbows','Not achieving full range of motion','Going too fast'],'{"cutting":"4x20","bulking":"3x20","maintenance":"3x15-20"}'),
('resistance-band-bicep-curl','Resistance Band Bicep Curl','arms','biceps brachii',ARRAY['forearms'],'resistance band','beginner',ARRAY['Stand on the middle of a resistance band with feet shoulder-width apart.','Hold an end in each hand at your sides.','Curl your hands toward your shoulders against the band resistance.','Lower slowly back down.'],ARRAY['Keep elbows pinned to your sides','The resistance increases as you curl — maintain control','Full extension at the bottom'],ARRAY['Elbows drifting forward','Not controlling the eccentric','Using a band with too little resistance'],'{"cutting":"3x20","bulking":"3x15 (double up band for more resistance)","maintenance":"3x15"}'),
('kettlebell-turkish-getup','Turkish Get-Up','full body','shoulders',ARRAY['core','glutes','quads','triceps'],'kettlebell','advanced',ARRAY['Lie on the floor with a kettlebell in one hand, pressed toward the ceiling.','Using a series of controlled movements, rise from lying to standing.','Keep the kettlebell locked out overhead throughout.','Reverse the sequence back to the floor.'],ARRAY['Eyes on the kettlebell at all times','Move slowly and deliberately — this is a skill movement','Each position should feel stable before moving to the next'],ARRAY['Moving too fast','Losing the locked-out position overhead','Looking away from the kettlebell'],'{"cutting":"3x3 each side","bulking":"3x3 each side, heavier","maintenance":"3x3 each side"}'),
('mountain-climber','Mountain Climber','core','rectus abdominis',ARRAY['hip flexors','shoulders','obliques'],'bodyweight','beginner',ARRAY['Start in a high push-up position with hands under shoulders.','Drive one knee toward your chest.','Quickly switch legs in a running motion.','Continue alternating at a controlled or fast pace.'],ARRAY['Keep your hips level — don''t let them rise','Brace your core throughout','Shoulders stay over your hands'],ARRAY['Hips rising up','Not fully driving the knee to the chest','Arms bending under load'],'{"cutting":"4x30 seconds","bulking":"3x20 seconds","maintenance":"3x30 seconds"}'),
('dumbbell-Romanian-deadlift','Dumbbell Romanian Deadlift','legs','hamstrings',ARRAY['glutes','erector spinae'],'dumbbell','beginner',ARRAY['Stand holding dumbbells in front of your thighs.','Hinge at the hips, pushing them back.','Lower dumbbells along the fronts of your legs until you feel a hamstring stretch.','Drive hips forward to return to standing.'],ARRAY['Soft knee bend throughout','Keep dumbbells close to your legs','Flat back — no rounding'],ARRAY['Bending the knees too much','Rounding the lower back','Not getting enough hip hinge'],'{"cutting":"3x15","bulking":"4x10, moderate weight","maintenance":"3x12"}'),
('incline-dumbbell-curl','Incline Dumbbell Curl','arms','biceps brachii',ARRAY['brachialis'],'dumbbell','intermediate',ARRAY['Set a bench to a 45-60 degree incline and sit back on it.','Let your arms hang straight down, dumbbells at your sides.','Curl both dumbbells up, supinating your wrists.','Lower slowly back to the starting position.'],ARRAY['The incline increases the range of motion and stretch on the biceps','Let the arms fully extend at the bottom for maximum stretch','Don''t swing the torso'],ARRAY['Swinging the torso to assist the lift','Partial range of motion','Going too heavy'],'{"cutting":"3x15, light weight","bulking":"4x10, moderate weight","maintenance":"3x12, moderate weight"}'),
('cable-row-single-arm','Single-Arm Cable Row','back','latissimus dorsi',ARRAY['rhomboids','biceps','rear deltoids'],'cable','beginner',ARRAY['Set a cable to lower chest height with a single handle attachment.','Sit or stand sideways and grip the handle.','Row the handle toward your hip, rotating slightly for a full contraction.','Return under control.'],ARRAY['Allow a slight torso rotation to maximize the range of motion','Drive the elbow behind you, not just your hand toward your hip','Initiate by retracting the shoulder blade'],ARRAY['Not allowing any rotation','Rotating too much and turning it into a cheat row','Using arm strength instead of pulling with the back'],'{"cutting":"3x15 each side","bulking":"4x10 each side","maintenance":"3x12 each side"}'),
('concentration-curl','Concentration Curl','arms','biceps brachii',ARRAY[],'dumbbell','beginner',ARRAY['Sit on a bench, lean forward, and brace your elbow on the inside of your thigh.','Hold a dumbbell in that hand.','Curl the dumbbell up toward your shoulder.','Lower slowly back down.'],ARRAY['The thigh is just a support — don''t actively push against it','Full supination at the top for peak contraction','Slow, deliberate reps'],ARRAY['Swinging the arm away from the thigh','Not supinating the wrist at the top','Going too heavy'],'{"cutting":"3x15 each arm","bulking":"4x10 each arm","maintenance":"3x12 each arm"}'),
('cable-bicep-curl','Cable Bicep Curl','arms','biceps brachii',ARRAY['brachialis'],'cable','beginner',ARRAY['Set a cable to the lowest position with a straight bar or EZ attachment.','Stand facing the machine and grip the attachment.','Curl upward to shoulder height.','Lower slowly under constant tension.'],ARRAY['Constant cable tension differs from free weights','Keep elbows stationary at your sides','The eccentric under constant tension is very effective'],ARRAY['Elbows drifting forward at the top','Not taking advantage of the constant tension','Using too much weight'],'{"cutting":"3x15, light-moderate weight","bulking":"4x10, moderate weight","maintenance":"3x12, moderate weight"}'),
('straight-arm-pulldown','Straight-Arm Pulldown','back','latissimus dorsi',ARRAY['triceps','rear deltoids'],'cable','beginner',ARRAY['Set a cable to the highest position with a straight bar.','Stand with a slight forward lean and grip the bar.','With arms straight, pull the bar down to your thighs.','Return slowly to the starting position.'],ARRAY['Arms stay straight throughout','Hinge slightly forward at the hips for a better angle','Feel the lats stretch at the top'],ARRAY['Bending the elbows','Standing too upright','Not getting a full stretch at the top'],'{"cutting":"3x15","bulking":"3x12, moderate weight","maintenance":"3x12"}'),
('dumbbell-shoulder-press','Dumbbell Shoulder Press','shoulders','deltoids',ARRAY['triceps','upper traps'],'dumbbell','beginner',ARRAY['Sit on a bench with back support, hold dumbbells at shoulder height.','Press both dumbbells upward until arms are fully extended.','Lower back to shoulder height under control.'],ARRAY['Keep your back pressed against the bench','Don''t fully lock out your elbows at the top','Exhale on the way up'],ARRAY['Arching the lower back off the bench','Using too much weight and losing control','Pressing at an angle rather than straight up'],'{"cutting":"3x15, moderate weight","bulking":"4x8-10, heavy weight","maintenance":"3x10-12, moderate weight"}'),
('band-hip-thrust','Resistance Band Hip Thrust','legs','glutes',ARRAY['hamstrings','abductors'],'resistance band','beginner',ARRAY['Sit with your upper back against a bench, band across your hips anchored under feet.','Drive your hips upward against the band resistance.','Squeeze your glutes at the top.','Lower hips back down.'],ARRAY['The band increases resistance at the top where glutes are strongest','Chin to chest to prevent lower back extension','Full hip extension at the top'],ARRAY['Not achieving full hip extension','Using too light a band','Hyperextending the lower back'],'{"cutting":"4x20","bulking":"4x15 (heavy band or add barbell)","maintenance":"3x15-20"}'),
('push-press','Push Press','shoulders','deltoids',ARRAY['triceps','quads','core','traps'],'barbell','intermediate',ARRAY['Hold the bar in a front rack position at shoulder height.','Perform a slight knee dip.','Drive through your legs and press the bar overhead explosively.','Lock out overhead and lower back to shoulders.'],ARRAY['The knee dip should be quick and shallow','The leg drive transitions into arm press seamlessly','Lock out fully overhead'],ARRAY['Too deep of a dip','Pushing the bar forward instead of straight up','Not using leg drive and just pressing'],'{"cutting":"3x10, moderate weight","bulking":"4x5-6, heavy weight","maintenance":"3x8, moderate weight"}'),
('cable-upright-row','Cable Upright Row','shoulders','lateral deltoids',ARRAY['traps','biceps'],'cable','beginner',ARRAY['Set a cable to the lowest position with a straight bar.','Stand and grip the bar with hands about shoulder-width apart.','Pull the bar upward toward your chin, elbows leading.','Lower slowly back to the starting position.'],ARRAY['Elbows should always be above hands','Keep the bar close to your body','Don''t pull excessively high'],ARRAY['Too narrow a grip','Pulling too high causing shoulder impingement','Using momentum'],'{"cutting":"3x15","bulking":"4x10","maintenance":"3x12"}'),
('decline-crunch','Decline Crunch','core','rectus abdominis',ARRAY['obliques'],'bodyweight','beginner',ARRAY['Sit on a decline bench and secure your feet.','Lie back and place hands behind your head.','Crunch your torso up toward your knees.','Lower slowly back down.'],ARRAY['The decline increases the range of motion for the abs','Don''t pull on the neck','Focus on spinal flexion rather than just sitting up'],ARRAY['Using hip flexors to pull up','Pulling on the neck','Not getting full range of motion'],'{"cutting":"4x20","bulking":"3x15 (hold a weight plate)","maintenance":"3x15-20"}'),
('v-up','V-Up','core','rectus abdominis',ARRAY['hip flexors','obliques'],'bodyweight','intermediate',ARRAY['Lie flat on your back with arms extended overhead.','Simultaneously raise your legs and torso to form a V shape.','Try to touch your toes at the top.','Lower back down slowly.'],ARRAY['Keep your legs straight throughout','The movement should be smooth, not jerky','Exhale as you come up'],ARRAY['Bending the knees','Using momentum instead of core strength','Not fully lowering between reps'],'{"cutting":"3x15","bulking":"3x15 (hold a dumbbell for resistance)","maintenance":"3x12-15"}'),
('woodchop','Cable Woodchop','core','obliques',ARRAY['transverse abdominis','shoulders','lats'],'cable','beginner',ARRAY['Set a cable to the highest position with a single handle.','Stand sideways to the machine and grip the handle with both hands.','Pull the handle diagonally downward toward the opposite hip.','Rotate your torso and pivot your back foot.','Return to the starting position.'],ARRAY['The movement comes from the torso rotation, not the arms','Keep your arms relatively straight','Pivot your back foot to allow full rotation'],ARRAY['Using the arms to pull instead of rotating','Not pivoting the back foot','Going too heavy'],'{"cutting":"3x15 each side","bulking":"3x12 each side","maintenance":"3x12-15 each side"}'),
('battle-ropes','Battle Ropes','full body','shoulders',ARRAY['core','arms','back','legs'],'bodyweight','intermediate',ARRAY['Anchor a thick rope to a fixed point at the base.','Hold one end in each hand, stand with a slight squat.','Create alternating waves by raising and lowering your arms.','Maintain the waves for the target duration.'],ARRAY['Stay low in your squat throughout for lower body engagement','The power comes from the whole body, not just the arms','Keep your core braced and back straight'],ARRAY['Standing too upright','Only using arms without body drive','Letting the ropes go slack'],'{"cutting":"5x30 seconds","bulking":"3x20 seconds, maximum intensity","maintenance":"4x30 seconds"}'),
('pull-and-press','Dumbbell Pull and Press','full body','full body',ARRAY['lats','shoulders','core','glutes'],'dumbbell','beginner',ARRAY['Stand holding dumbbells, hinge forward and row them to your hips.','Stand up and curl the dumbbells to your shoulders.','Press overhead to full extension.','Reverse the movement to the starting position.'],ARRAY['Each phase should be deliberate and controlled','Full extension on the press','Keep your core engaged throughout'],ARRAY['Rushing through the phases','Using momentum','Arching the back during the press'],'{"cutting":"3x12","bulking":"4x10","maintenance":"3x10"}'),
('man-maker','Man Maker','full body','full body',ARRAY['chest','shoulders','back','core','legs'],'dumbbell','advanced',ARRAY['Start standing, holding dumbbells.','Squat down and place dumbbells on floor.','Jump feet back to push-up position.','Perform a push-up.','Row each dumbbell while in plank.','Jump feet forward and clean dumbbells to shoulders.','Press overhead.'],ARRAY['Control each phase — this is a skill movement','Core stays braced throughout especially during the row','Maintain neutral spine in the plank position'],ARRAY['Rushing and losing form','Hips rising too high in the plank position','Not performing a full push-up'],'{"cutting":"3x6","bulking":"3x5, heavier dumbbells","maintenance":"3x5-6"}'),
('kettlebell-goblet-squat','Kettlebell Goblet Squat','legs','quadriceps',ARRAY['glutes','core','adductors'],'kettlebell','beginner',ARRAY['Hold a kettlebell by the horns at chest height.','Stand with feet slightly wider than hip-width, toes turned out.','Sit down between your heels into a deep squat.','Drive through your heels to stand.'],ARRAY['Use elbows to push knees outward at the bottom','Chest stays tall throughout','Try to achieve full depth'],ARRAY['Heels rising off the floor','Torso collapsing forward','Knees caving inward'],'{"cutting":"3x15","bulking":"4x10, heavy kettlebell","maintenance":"3x12"}')
