-- Create exercises table
CREATE TABLE IF NOT EXISTS exercises (
  id text PRIMARY KEY,
  name text NOT NULL,
  body_part text NOT NULL,
  target_muscle text NOT NULL,
  secondary_muscles text[],
  equipment text NOT NULL,
  difficulty text NOT NULL,
  instructions text[],
  form_cues text[],
  common_mistakes text[],
  sets_reps_guidance jsonb,
  created_at timestamp DEFAULT now()
);

-- Enable RLS
ALTER TABLE exercises ENABLE ROW LEVEL SECURITY;

-- Allow everyone to read exercises (public data)
CREATE POLICY "Anyone can read exercises" ON exercises
  FOR SELECT USING (true);

-- Only service role can insert/update
CREATE POLICY "Service role can manage exercises" ON exercises
  FOR ALL USING (auth.role() = 'service_role');

-- Seed data
ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name,
  body_part = EXCLUDED.body_part,
  target_muscle = EXCLUDED.target_muscle,
  secondary_muscles = EXCLUDED.secondary_muscles,
  equipment = EXCLUDED.equipment,
  difficulty = EXCLUDED.difficulty,
  instructions = EXCLUDED.instructions,
  form_cues = EXCLUDED.form_cues,
  common_mistakes = EXCLUDED.common_mistakes,
  sets_reps_guidance = EXCLUDED.sets_reps_guidance;
